package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatWithSkipHeaderRecordTest {

    @Test
    void testWithSkipHeaderRecord_defaultTrue() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withSkipHeaderRecord(true);
        assertNotNull(newFormat);
        assertTrue(newFormat.getSkipHeaderRecord());
        // Original format should remain unchanged
        assertFalse(format.getSkipHeaderRecord());
    }

    @Test
    void testWithSkipHeaderRecord_falseToTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(false);
        assertFalse(format.getSkipHeaderRecord());
        CSVFormat newFormat = format.withSkipHeaderRecord(true);
        assertTrue(newFormat.getSkipHeaderRecord());
    }

    @Test
    void testWithSkipHeaderRecord_idempotent() {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(true);
        CSVFormat newFormat = format.withSkipHeaderRecord(true);
        // Should return the same instance if already true (assuming immutability)
        assertSame(format, newFormat);
    }
}
